'use strict';
function createRollback(steps) {
  const executed = [];
  return {
    execute(stepName) {
      const step = steps.find(s => s.name === stepName);
      if (!step) throw new Error('unknown step: ' + stepName);
      step.execute();
      executed.push({ name: stepName, timestamp: Date.now() });
    },
    undo() {
      while (executed.length > 0) {
        const last = executed.pop();
        const step = steps.find(s => s.name === last.name);
        if (step && step.undo) step.undo();
      }
    },
    getHistory() { return [...executed]; }
  };
}
module.exports = { createRollback };
